RK_RES test_init_ec_pubkey(rk_ec_pub_key_pack *pub, enum RK_EC_CURVE curve)
{
	memset(pub, 0, sizeof(*pub));

	switch (curve) {
	case RK_EC_CURVE_SM2:
		pub->key.curve = curve;
		pub->key.x = ecc_sm2_x;
		pub->key.y = ecc_sm2_y;
		pub->key.x_len = sizeof(ecc_sm2_x);
		pub->key.y_len = sizeof(ecc_sm2_y);
		break;
	case RK_EC_CURVE_P192:
		pub->key.curve = curve;
		pub->key.x = ecc_p192_x;
		pub->key.y = ecc_p192_y;
		pub->key.x_len = sizeof(ecc_p192_x);
		pub->key.y_len = sizeof(ecc_p192_y);
		break;
	case RK_EC_CURVE_P224:
		pub->key.curve = curve;
		pub->key.x = ecc_p224_x;
		pub->key.y = ecc_p224_y;
		pub->key.x_len = sizeof(ecc_p224_x);
		pub->key.y_len = sizeof(ecc_p224_y);
		break;
	case RK_EC_CURVE_P256:
		pub->key.curve = curve;
		pub->key.x = ecc_p256_x;
		pub->key.y = ecc_p256_y;
		pub->key.x_len = sizeof(ecc_p256_x);
		pub->key.y_len = sizeof(ecc_p256_y);
		break;
	case RK_EC_CURVE_P384:
		pub->key.curve = curve;
		pub->key.x = ecc_p384_x;
		pub->key.y = ecc_p384_y;
		pub->key.x_len = sizeof(ecc_p384_x);
		pub->key.y_len = sizeof(ecc_p384_y);
		break;
	case RK_EC_CURVE_P521:
		pub->key.curve = curve;
		pub->key.x = ecc_p521_x;
		pub->key.y = ecc_p521_y;
		pub->key.x_len = sizeof(ecc_p521_x);
		pub->key.y_len = sizeof(ecc_p521_y);
		break;
	default:
		return RK_CRYPTO_ERR_PARAMETER;
	}

	return RK_CRYPTO_SUCCESS;
}

RK_RES test_init_ec_privkey(rk_ec_priv_key_pack *priv, enum RK_EC_CURVE curve)
{
	memset(priv, 0, sizeof(*priv));

	switch (curve) {
	case RK_EC_CURVE_SM2:
		priv->key.curve = curve;
		priv->key.x = ecc_sm2_x;
		priv->key.y = ecc_sm2_y;
		priv->key.d = ecc_sm2_d;
		priv->key.x_len = sizeof(ecc_sm2_x);
		priv->key.y_len = sizeof(ecc_sm2_y);
		priv->key.d_len = sizeof(ecc_sm2_d);
		break;
	case RK_EC_CURVE_P192:
		priv->key.curve = curve;
		priv->key.x = ecc_p192_x;
		priv->key.y = ecc_p192_y;
		priv->key.d = ecc_p192_d;
		priv->key.x_len = sizeof(ecc_p192_x);
		priv->key.y_len = sizeof(ecc_p192_y);
		priv->key.d_len = sizeof(ecc_p192_d);
		break;
	case RK_EC_CURVE_P224:
		priv->key.curve = curve;
		priv->key.x = ecc_p224_x;
		priv->key.y = ecc_p224_y;
		priv->key.d = ecc_p224_d;
		priv->key.x_len = sizeof(ecc_p224_x);
		priv->key.y_len = sizeof(ecc_p224_y);
		priv->key.d_len = sizeof(ecc_p224_d);
		break;
	case RK_EC_CURVE_P256:
		priv->key.curve = curve;
		priv->key.x = ecc_p256_x;
		priv->key.y = ecc_p256_y;
		priv->key.d = ecc_p256_d;
		priv->key.x_len = sizeof(ecc_p256_x);
		priv->key.y_len = sizeof(ecc_p256_y);
		priv->key.d_len = sizeof(ecc_p256_d);
		break;
	case RK_EC_CURVE_P384:
		priv->key.curve = curve;
		priv->key.x = ecc_p384_x;
		priv->key.y = ecc_p384_y;
		priv->key.d = ecc_p384_d;
		priv->key.x_len = sizeof(ecc_p384_x);
		priv->key.y_len = sizeof(ecc_p384_y);
		priv->key.d_len = sizeof(ecc_p384_d);
		break;
	case RK_EC_CURVE_P521:
		priv->key.curve = curve;
		priv->key.x = ecc_p521_x;
		priv->key.y = ecc_p521_y;
		priv->key.d = ecc_p521_d;
		priv->key.x_len = sizeof(ecc_p521_x);
		priv->key.y_len = sizeof(ecc_p521_y);
		priv->key.d_len = sizeof(ecc_p521_d);
		break;
	default:
		printf("Unknown curve: %d\n", curve);
		return RK_CRYPTO_ERR_PARAMETER;
	}

	return RK_CRYPTO_SUCCESS;
}